import json
import boto3
import os
from datetime import datetime
from botocore.exceptions import ClientError

s3_client = boto3.client('s3')
sns_client = boto3.client('sns')

def lambda_handler(event, context):
    """
    Lambda function to process user-uploaded images from S3.
    
    IAM Role Policy (Least Privilege):
    {
        "Version": "2012-10-17",
        "Statement": [
            {
                "Effect": "Allow",
                "Action": [
                    "s3:GetObject"
                ],
                "Resource": "arn:aws:s3:::${SOURCE_BUCKET_NAME}/*"
            },
            {
                "Effect": "Allow",
                "Action": [
                    "s3:PutObject"
                ],
                "Resource": "arn:aws:s3:::${DESTINATION_BUCKET_NAME}/*"
            },
            {
                "Effect": "Allow",
                "Action": [
                    "sns:Publish"
                ],
                "Resource": "arn:aws:sns:${REGION}:${ACCOUNT_ID}:${SNS_TOPIC_NAME}"
            },
            {
                "Effect": "Allow",
                "Action": [
                    "logs:CreateLogGroup",
                    "logs:CreateLogStream",
                    "logs:PutLogEvents"
                ],
                "Resource": "arn:aws:logs:${REGION}:${ACCOUNT_ID}:log-group:/aws/lambda/${FUNCTION_NAME}:*"
            }
        ]
    }
    
    Environment Variables Required:
    - DESTINATION_BUCKET: S3 bucket for processed results
    - SNS_TOPIC_ARN: ARN of SNS topic for notifications
    - ALLOWED_SOURCE_BUCKETS: Comma-separated list of allowed source bucket names
    """
    
    try:
        destination_bucket = os.environ.get('DESTINATION_BUCKET')
        sns_topic_arn = os.environ.get('SNS_TOPIC_ARN')
        allowed_buckets = os.environ.get('ALLOWED_SOURCE_BUCKETS', '').split(',')
        
        if not destination_bucket or not sns_topic_arn:
            raise ValueError("Missing required environment variables")
        
        for record in event['Records']:
            source_bucket = record['s3']['bucket']['name']
            object_key = record['s3']['object']['key']
            
            if source_bucket not in allowed_buckets:
                print(f"Bucket {source_bucket} not in allowed list. Skipping.")
                continue
            
            if not is_valid_image_key(object_key):
                print(f"Invalid or potentially unsafe object key: {object_key}. Skipping.")
                continue
            
            print(f"Processing image: {object_key} from bucket: {source_bucket}")
            
            image_data = s3_client.get_object(
                Bucket=source_bucket,
                Key=object_key
            )
            
            image_content = image_data['Body'].read()
            content_type = image_data.get('ContentType', 'application/octet-stream')
            
            if not is_valid_image_content_type(content_type):
                print(f"Invalid content type: {content_type}. Skipping.")
                continue
            
            processed_result = process_image(image_content, object_key)
            
            result_key = f"processed/{datetime.utcnow().strftime('%Y/%m/%d')}/{sanitize_filename(object_key)}.json"
            
            s3_client.put_object(
                Bucket=destination_bucket,
                Key=result_key,
                Body=json.dumps(processed_result),
                ContentType='application/json',
                ServerSideEncryption='AES256'
            )
            
            print(f"Results written to: {result_key}")
            
            notification_message = {
                'source_bucket': source_bucket,
                'source_key': object_key,
                'result_bucket': destination_bucket,
                'result_key': result_key,
                'timestamp': datetime.utcnow().isoformat(),
                'status': 'success'
            }
            
            sns_client.publish(
                TopicArn=sns_topic_arn,
                Subject='Image Processing Complete',
                Message=json.dumps(notification_message)
            )
            
            print(f"Notification sent for: {object_key}")
        
        return {
            'statusCode': 200,
            'body': json.dumps({'message': 'Processing complete'})
        }
        
    except ClientError as e:
        error_message = f"AWS service error: {str(e)}"
        print(error_message)
        send_error_notification(sns_topic_arn, error_message)
        raise
        
    except Exception as e:
        error_message = f"Processing error: {str(e)}"
        print(error_message)
        send_error_notification(sns_topic_arn, error_message)
        raise


def is_valid_image_key(key):
    """Validate S3 object key to prevent path traversal and injection attacks"""
    if not key:
        return False
    
    dangerous_patterns = ['..', '//', '\\', '\x00']
    for pattern in dangerous_patterns:
        if pattern in key:
            return False
    
    allowed_extensions = ['.jpg', '.jpeg', '.png', '.gif', '.bmp', '.webp']
    return any(key.lower().endswith(ext) for ext in allowed_extensions)


def is_valid_image_content_type(content_type):
    """Validate content type to ensure only images are processed"""
    allowed_types = [
        'image/jpeg',
        'image/png',
        'image/gif',
        'image/bmp',
        'image/webp'
    ]
    return content_type in allowed_types


def sanitize_filename(filename):
    """Sanitize filename to prevent injection attacks"""
    import re
    safe_filename = re.sub(r'[^a-zA-Z0-9._-]', '_', filename)
    return safe_filename[:255]


def process_image(image_content, object_key):
    """Process the image and return results"""
    result = {
        'original_key': object_key,
        'size_bytes': len(image_content),
        'processed_at': datetime.utcnow().isoformat(),
        'status': 'processed'
    }
    
    return result


def send_error_notification(sns_topic_arn, error_message):
    """Send error notification via SNS"""
    if not sns_topic_arn:
        return
    
    try:
        sns_client.publish(
            TopicArn=sns_topic_arn,
            Subject='Image Processing Error',
            Message=json.dumps({
                'status': 'error',
                'error': error_message,
                'timestamp': datetime.utcnow().isoformat()
            })
        )
    except Exception as e:
        print(f"Failed to send error notification: {str(e)}")